 60→func ParseTranscript(content string) ([]TranscriptEntry, error) {
 61→	var entries []TranscriptEntry
 62→
 63→	scanner := bufio.NewScanner(strings.NewReader(content))
 64→	buf := make([]byte, 0, 1024*1024)
 65→	scanner.Buffer(buf, 10*1024*1024)
 66→
 67→	for scanner.Scan() {
 68→		line := scanner.Bytes()
 69→		if len(line) == 0 {
 70→			continue
 71→		}
 72→
 73→		var entry jsonlEntry
 74→		if err := json.Unmarshal(line, &entry); err != nil {
 75→			continue
 76→		}
 77→
 78→		text, toolName := extractContent(entry)
 79→
 80→		role := entry.Role
 81→		if role == "" {
 82→			role = entry.Type
 83→		}
 84→
 85→		entries = append(entries, TranscriptEntry{
 86→			Type:      entry.Type,
 87→			Role:      role,
 88→			Content:   text,
 89→			ToolName:  toolName,
 90→			Timestamp: entry.Timestamp.Time,
 91→		})
 92→	}
 93→
 94→	return entries, scanner.Err()
 95→}
