100→	if len(entry.ContentBlocks) > 0 {
101→		var text string
102→		for _, b := range entry.ContentBlocks {
103→			switch b.Type {
104→			case "text":
105→				text += b.Text
106→			case "tool_use":
107→				toolName = b.Name
108→			}
109→		}
110→		return text, toolName
111→	}
112→
113→	if entry.Message != nil {
114→		var mc messageContent
115→		if json.Unmarshal(entry.Message, &mc) == nil && len(mc.Content) > 0 {
116→			var text string
117→			for _, b := range mc.Content {
118→				switch b.Type {
119→				case "text":
120→					text += b.Text
121→				case "tool_use":
122→					toolName = b.Name
123→				}
124→			}
125→			return text, toolName
126→		}
127→
128→		var s string
129→		if json.Unmarshal(entry.Message, &s) == nil {
130→			return s, ""
131→		}
132→	}
133→
134→	if entry.Content != nil {
135→		var blocks []contentBlock
136→		if json.Unmarshal(entry.Content, &blocks) == nil && len(blocks) > 0 {
137→			var text string
138→			for _, b := range blocks {
139→				switch b.Type {
140→				case "text":
141→					text += b.Text
142→				case "tool_use":
143→					toolName = b.Name
144→				}
145→			}
146→			return text, toolName
147→		}
148→
149→		var s string
