 49→func groupTranscriptEntries(entries []checkpoint.TranscriptEntry) []messageGroup {
 50→	var groups []messageGroup
 51→	var pendingTools []string
 52→	pendingResults := 0
 53→
 54→	flushTools := func() {
 55→		if len(pendingTools) > 0 || pendingResults > 0 {
 56→			groups = append(groups, messageGroup{
 57→				role:    "tools",
 58→				tools:   pendingTools,
 59→				results: pendingResults,
 60→			})
 61→			pendingTools = nil
 62→			pendingResults = 0
 63→		}
 64→	}
 65→
 66→	for _, e := range entries {
 67→		switch {
 68→		case e.Role == "human" || e.Role == "user":
 69→			if e.Content == "" {
 70→				continue
 71→			}
 72→			flushTools()
 73→			ts := ""
 74→			if !e.Timestamp.IsZero() {
 75→				ts = e.Timestamp.Format("3:04 PM")
 76→			}
 77→			groups = append(groups, messageGroup{
 78→				role:    "user",
 79→				content: e.Content,
 80→				ts:      ts,
 81→			})
 82→
 83→		case e.Role == "assistant" && e.ToolName != "":
 84→			pendingTools = append(pendingTools, e.ToolName)
 85→
 86→		case e.Role == "assistant":
 87→			if e.Content == "" {
 88→				continue
 89→			}
 90→			flushTools()
 91→			ts := ""
 92→			if !e.Timestamp.IsZero() {
 93→				ts = e.Timestamp.Format("3:04 PM")
 94→			}
 95→			groups = append(groups, messageGroup{
 96→				role:    "assistant",
 97→				content: e.Content,
 98→				ts:      ts,
 99→			})
100→
101→		case e.Type == "tool_result":
102→			pendingResults++
103→
104→		default:
105→			if e.Content != "" {
106→				flushTools()
107→				groups = append(groups, messageGroup{
108→					role:    "other",
109→					content: e.Content,
110→				})
111→			}
112→		}
113→	}
