118→func renderTabTranscript(entries []checkpoint.TranscriptEntry, width, height, scrollOffset int) string {
119→	if len(entries) == 0 {
120→		return dimStyle.Render("  Loading transcript...")
121→	}
122→
123→	contentWidth := width - 8
124→	if contentWidth < 30 {
125→		contentWidth = 30
126→	}
127→
128→	var allLines []string
129→
130→	messageCount := 0
131→	for _, e := range entries {
132→		if (e.Role == "human" || e.Role == "user" || e.Role == "assistant") && e.Content != "" && e.ToolName == "" {
133→			messageCount++
134→		}
135→	}
136→
137→	allLines = append(allLines,
138→		sectionHeaderStyle.Render(fmt.Sprintf("  Transcript (%d messages)", messageCount)),
139→		"",
140→	)
141→
142→	groups := groupTranscriptEntries(entries)
143→
144→	for _, g := range groups {
145→		switch g.role {
146→		case "user":
147→			label := userLabelStyle.Render("You")
148→			if g.ts != "" {
149→				pad := contentWidth - lipgloss.Width(label) - len(g.ts)
150→				if pad < 2 {
151→					pad = 2
152→				}
153→				allLines = append(allLines, "  "+label+strings.Repeat(" ", pad)+timestampStyle.Render(g.ts))
154→			} else {
155→				allLines = append(allLines, "  "+label)
156→			}
157→
158→			wrapped := wordWrap(g.content, contentWidth-4)
159→			block := userBorderStyle.Width(contentWidth).Render(wrapped)
160→			for _, line := range strings.Split(block, "\n") {
161→				allLines = append(allLines, "  "+line)
162→			}
163→			allLines = append(allLines, "")
164→
165→		case "assistant":
166→			label := assistantLabelStyle.Render("Assistant")
167→			if g.ts != "" {
168→				pad := contentWidth - lipgloss.Width(label) - len(g.ts)
169→				if pad < 2 {
170→					pad = 2
171→				}
172→				allLines = append(allLines, "    "+label+strings.Repeat(" ", pad)+timestampStyle.Render(g.ts))
173→			} else {
174→				allLines = append(allLines, "    "+label)
175→			}
176→
177→			rendered := renderMarkdown(g.content, contentWidth-6)
178→			block := assistantBorderStyle.Width(contentWidth).Render(rendered)
179→			for _, line := range strings.Split(block, "\n") {
180→				allLines = append(allLines, "    "+line)
181→			}
182→			allLines = append(allLines, "")
183→
184→		case "tools":
185→			var badges []string
186→			for _, t := range g.tools {
187→				badges = append(badges, toolBadgeStyle.Render("["+t+"]"))
188→			}
189→			if len(badges) > 0 {
190→				allLines = append(allLines, "    "+strings.Join(badges, " "))
191→			}
192→			if g.results > 0 {
193→				allLines = append(allLines, "    "+toolResultStyle.Render(fmt.Sprintf("[%d results]", g.results)))
194→			}
195→			allLines = append(allLines, "")
196→
197→		case "other":
198→			content := g.content
199→			if len(content) > contentWidth {
200→				content = content[:contentWidth-3] + "..."
201→			}
202→			allLines = append(allLines, "  "+content)
203→			allLines = append(allLines, "")
204→		}
205→	}
206→
207→	maxScroll := len(allLines) - height
208→	if maxScroll < 0 {
209→		maxScroll = 0
210→	}
211→	if scrollOffset > maxScroll {
212→		scrollOffset = maxScroll
213→	}
214→	if scrollOffset < 0 {
215→		scrollOffset = 0
216→	}
217→
218→	end := scrollOffset + height
219→	if end > len(allLines) {
220→		end = len(allLines)
221→	}
222→
223→	visible := allLines[scrollOffset:end]
224→
225→	if maxScroll > 0 {
226→		pos := scrollIndicatorStyle.Render(fmt.Sprintf("(%d/%d)", scrollOffset+1, maxScroll+1))
227→		visible = append(visible, "  "+pos)
228→	}
229→
230→	return strings.Join(visible, "\n")
231→}
